以下是使用Java实现基于SM4算法的CBC工作模式的示例代码。

代码依赖于Bouncy Castle库，因此需要先下载并将其添加到项目中。

注意，以下是示例代码，请根据实际情况进行修改和调整。

```java
import org.bouncycastle.crypto.BlockCipher;
import org.bouncycastle.crypto.engines.SM4Engine;
import org.bouncycastle.crypto.modes.CBCBlockCipher;
import org.bouncycastle.crypto.params.KeyParameter;
import org.bouncycastle.crypto.params.ParametersWithIV;
import org.bouncycastle.util.encoders.Hex;

import java.security.SecureRandom;

public class SM4CBC {

    private byte[] key;
    private byte[] iv;

    public SM4CBC(String keyStr, String ivStr) {
        key = Hex.decode(keyStr);
        iv = Hex.decode(ivStr);
    }

    public byte[] encrypt(byte[] plaintext) throws Exception {
        BlockCipher engine = new SM4Engine();
        CBCBlockCipher cbc = new CBCBlockCipher(engine);
        ParametersWithIV params = new ParametersWithIV(new KeyParameter(key), iv);
        cbc.init(true, params);
        byte[] ciphertext = new byte[cbc.getOutputSize(plaintext.length)];
        int len = cbc.processBytes(plaintext, 0, plaintext.length, ciphertext, 0);
        cbc.doFinal(ciphertext, len);
        return ciphertext;
    }

    public byte[] decrypt(byte[] ciphertext) throws Exception {
        BlockCipher engine = new SM4Engine();
        CBCBlockCipher cbc = new CBCBlockCipher(engine);
        ParametersWithIV params = new ParametersWithIV(new KeyParameter(key), iv);
        cbc.init(false, params);
        byte[] plaintext = new byte[cbc.getOutputSize(ciphertext.length)];
        int len = cbc.processBytes(ciphertext, 0, ciphertext.length, plaintext, 0);
        cbc.doFinal(plaintext, len);
        return plaintext;
    }

